using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF9: HasIndex now throws for Cosmos — indexing is managed via Azure portal/Bicep.

            // EF9: Default discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents and raw SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF9: id no longer contains discriminator prefix (was "Blog|1", now "1").
            // Preserve old format so existing documents remain accessible.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
